import React, { useState, useEffect, useRef } from "react";
import './all-layout.scss';
import Dropdown from "../dropdown/dropdown";
import { useDispatch, useSelector } from "react-redux";

import { __ } from '@wordpress/i18n';
import NoTemplate from "../no-template/no-template";
import { nxtInstallCall } from "../../apicall";

const AllLayout = ({menuActive, menuActiveLabel}) => {

    const [selectTemp, setSelectTemp] = useState({});
    const [action, setAction] = useState({});
    const [searchTerm, setSearchTerm] = useState("");
    const ThemeBuilderList = useSelector((state) => state.templates);
    const statusLoadingId = useSelector(
        (state) => state.statusLoadingId
    );
    
    const trashLoadingId = useSelector(
        (state) => state.trashLoadingId
    );
    
    const createTemp = [
        {
            type: 'header',
            img: 'header.svg',
            title: __("Create Header", 'nexter-extension'),
            docs: '#',
            btn : __("Add Header", 'nexter-extension'),
            wdk : 1017,
        },
        {
            type: 'footer',
            img: 'footer.svg',
            title: __("Create Footer", 'nexter-extension'),
            docs: '#',
            btn : __("Add Footer", 'nexter-extension'),
            wdk : 1018,
        },
        {
            type: 'breadcrumb',
            img: 'breadcrumb.svg',
            title: __("Create Breadcrumb", 'nexter-extension'),
            docs: '#',
            btn : __("Add Breadcrumb", 'nexter-extension'),
            wdk : 1017,
        },
        {
            type: 'section',
            img: 'section.svg',
            title: __("Create Section", 'nexter-extension'),
            docs: '#',
            btn : __("Add Section", 'nexter-extension'),
            wdk : 1002
        },
        {
            type: 'singular',
            img: 'singular.svg',
            title: __("Create Singular", 'nexter-extension'),
            docs: '#',
            btn : __("Add Singular", 'nexter-extension'),
            wdk : 1009,
        },
        {
            type: 'archives',
            img: 'archives.svg',
            title: __("Create Archive Page", 'nexter-extension'),
            docs: '#',
            btn : __("Add Archive", 'nexter-extension'),
            wdk : 1010,
        },
        {
            type: 'hooks',
            img: 'hooks.svg',
            title: __("Create Hooks", 'nexter-extension'),
            docs: '#',
            btn : __("Add Hooks", 'nexter-extension'),
            wdk : 1002,
        },
        {
            type: 'page-404',
            img: 'page-404.svg',
            title: __("Create 404 Page", 'nexter-extension'),
            docs: '#',
            btn : __("Add 404 Page", 'nexter-extension'),
            wdk : 1012,
        },
    ]
    const [isPopupOpen, setIsPopupOpen] = useState(false);

    const openPopup = (e) => {
        e.preventDefault();
        setIsPopupOpen(true);
    };

    const closePopup = () => {
        setIsPopupOpen(false);
    };

    const [isWDKPopupOpen, setIsWDKPopupOpen] = useState(false);

    const openWDKPopup = () => setIsWDKPopupOpen(true);
    const closeWDKPopup = () => setIsWDKPopupOpen(false);

    const addNewDropdownItems = [
        { label: __("Header", 'nexter-extension'), value: "header" },
        { label: __("Footer", 'nexter-extension'), value: "footer" },
        { label: __("Breadcrumb", 'nexter-extension'), value: "breadcrumb" },
        { label: __("Sections", 'nexter-extension'), value: "section" },
        { label: __("Single Page", 'nexter-extension'), value: "singular" },
        { label: __("Archive Page", 'nexter-extension'), value: "archives" },
        { label: __("Hooks", 'nexter-extension'), value: "hooks" },
        { label: __("404 Page", 'nexter-extension'), value: "page-404" },
    ];

    const dotsSVG = (
        <svg xmlns="http://www.w3.org/2000/svg" width="15" height="4" fill="none" viewBox="0 0 15 4"><path fill="#1a1a1a" d="M8.58 2.006a1.485 1.485 0 1 1-2.972 0v-.01a1.486 1.486 0 1 1 2.971 0zm-5.61-.009a1.485 1.485 0 1 1-2.97 0v-.01a1.486 1.486 0 1 1 2.97 0zm11.218.018a1.485 1.485 0 1 1-2.971 0v-.01a1.486 1.486 0 1 1 2.97 0z"/></svg>

    );

    const addNewSVG = (
        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#fff" d="m4.5 6.75 4.5 4.5 4.5-4.5"/></svg>
    )

    const dotsDropdownItems = [
        { label: __("Edit Conditions", 'nexter-extension'), value: "edit_conditions" },
        { label: __("Preview", 'nexter-extension'), value: "preview" },
        { label: __("Copy Shortcode", 'nexter-extension'), value: "copy_shortcode" },
        { label: __("Export Template", 'nexter-extension'), value: "export" },
        ...(nexter_theme_builder_config?.duplicateEnabled ? [{ label: __("Duplicate", 'nexter-extension'), value: "duplicate" }] : []),
        { label: __('Status', 'nexter-extension'), value: "status" },
        { label: __("Trash", 'nexter-extension'), value: "trash" },
    ];

    if (!ThemeBuilderList) {
        return <div className="nxt-temp-loading"><img src={nexter_theme_builder_config.assets+'images/loading.gif'} alt="" /></div>;
    }
    
    const filteredList = (ThemeBuilderList && ThemeBuilderList.length > 0) && ThemeBuilderList.filter((item) => {
        // Menu filter
        const matchMenu = menuActive === 'all' || item.type_slug === menuActive;

        // Search filter
        const term = searchTerm.toLowerCase();
        const matchSearch =
            item.name.toLowerCase().includes(term) ||
            item.section_page.toLowerCase().includes(term) ||
            item.type_title.toLowerCase().includes(term) ||
            item.type_slug.toLowerCase().includes(term);

        // Return only items that match both
        return matchMenu && matchSearch;
    }) || [];

    const handleNewClick = (e, type='') => {
        const builder = new window.NexterBuilder();
        let action = 'action=nexter_ext_temp_popup&nexter_nonce=' + nexter_theme_builder_config.ajax_nonce;
        builder.nxtBuilderCommon(action, true, type);
    }

    const checkSVG = (<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 16 16"><path fill="gray" d="M12.305 3.988a.5.5 0 0 1 .724.69l-7 7.333a.5.5 0 0 1-.715.009L2.98 9.686a.5.5 0 0 1 .67-.741l.037.034 1.972 1.972z"/></svg>); 

    const getWDKbyType = () => {
        const item = createTemp.find(el => el.type === menuActive);
        return item ? item.wdk : 1017;
    };

    return (
        <div className="nxt-temp-all-layout">
            <div className="nxt-temp-alllot-toph">
                <div className="nxt-temp-all-srh">
                    <input type="search" placeholder={__('Search', 'nexter-extension')} className="nxt-temp-srh" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}/>
                    <svg className="nxt-temp-sr-icon" width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M14.0005 13.9995L10.5359 10.5349M10.5359 10.5349C11.4736 9.59716 12.0004 8.32534 12.0004 6.99921C12.0004 5.67308 11.4736 4.40126 10.5359 3.46354C9.59814 2.52583 8.32632 1.99902 7.00019 1.99902C5.67406 1.99902 4.40224 2.52583 3.46452 3.46354C2.5268 4.40126 2 5.67308 2 6.99921C2 8.32534 2.5268 9.59716 3.46452 10.5349C4.40224 11.4726 5.67406 11.9994 7.00019 11.9994C8.32632 11.9994 9.59814 11.4726 10.5359 10.5349Z" stroke="#666666" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" /></svg>
                </div>
                {!(nexter_theme_builder_config.is_pro == '1' && (nxtext_ajax_object?.dashData?.whiteLabel?.nxt_template_tab == 'on' || nxtext_ajax_object?.dashData?.whiteLabel?.nxt_wdk_integration == 'on')) && nexter_theme_builder_config.extensioninstall== '1' &&
                    <button className="nxt-temp-blk-btn naxt-temp-otline-btn" type="button" onClick={() => {
                        if (nexter_theme_builder_config.wdkPlugin == false) {
                            openWDKPopup();
                        } else {
                            window.WdkitThemeBuilderToggle.open(null, null, getWDKbyType());
                        }
                    }}>{__('Import Pre-Designed Section', 'nexter-extension')}</button>
                }

                {isWDKPopupOpen && !(nexter_theme_builder_config.is_pro == '1' && nxtext_ajax_object?.dashData?.whiteLabel?.nxt_wdk_integration == 'on') && (
                    <>
                        <div className="nxt-temp-overlay" onClick={closeWDKPopup}></div>
                        <div className="nxt-temp-popup nxt-temp-wdk-popup">
                            <div className="nxt-temp-pop-header">
                                <img src={nexter_theme_builder_config.assets+'images/wdesignkit-logo.png'} alt={__('WDesignKit', 'nexter-extension')} />
                                <button className="nxt-temp-close-btn" onClick={closeWDKPopup}><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="none" viewBox="0 0 20 20"><path fill="gray" d="M15.393 3.725a.625.625 0 1 1 .883.884L10.885 10l5.391 5.392.044.047a.625.625 0 0 1-.88.88l-.047-.043L10 10.884 4.61 16.276a.625.625 0 1 1-.884-.884L9.117 10 3.726 4.61a.625.625 0 1 1 .884-.884L10 9.116z"/></svg></button>
                            </div>

                            <div className="nxt-temp-pop-body">
                                <div className="nxt-temp-pop-heading">
                                    <h3>{__('Import Pre-Designed Templates for Theme Builder', 'nexter-extension')}</h3>
                                    <div className="nxt-features-dic">
                                        <ul>
                                            <li>
                                                {checkSVG}
                                                <span>{__('Build your website faster with ready-to-use templates', 'nexter-extension')}</span>
                                            </li>
                                            <li>
                                               {checkSVG}
                                                <span>{__('Fully customizable to match your brand and style', 'nexter-extension')}</span>
                                            </li>
                                            <li>
                                                {checkSVG}
                                                <span>{__('Save time by avoiding repetitive design work', 'nexter-extension')}</span>
                                            </li>
                                            <li>
                                                {checkSVG}
                                                <span>{__('Flexible layouts for headers, footers, pages, and more', 'nexter-extension')}</span>
                                            </li>
                                        </ul>
                                    </div>
                                </div>
                                <div className="nxt-install-activate">
                                    <a className='nxt-install-btn' onClick={(e) => nxtInstallCall(e, true,"wdesignkit")}>{nexter_theme_builder_config?.wdkactive ? __('Activate WDesignKit to Import Templates', 'nexter-extension') : __('Install WDesignKit to Import Templates', 'nexter-extension')}</a>
                                    {/* <a className='nxt-learn-more' href='https://wdesignkit.com/?utm_source=wpbackend&utm_medium=banner&utm_campaign=nextersettings' target='_blank' rel="noopener noreferrer">{__('Design from Scratch', 'nexter-extension')}</a> */}
                                </div>
                                <div className="nxt-pop-bottom-banner" style={{backgroundImage: `url(${nexter_theme_builder_config.assets+'images/wdesignkit-banner.png'})`}}>
                                    {/* <img src={nexter_theme_builder_config.assets+'images/wdesignkit-banner.png'} alt={__("WDesignKit Banner", 'nexter-extension')} /> */}
                                </div>
                            </div>
                        </div>
                    </>
                )}
                <div className="nxt-temp-adn-dp">
                    {nexter_theme_builder_config.extensioninstall != '1' ? 
                        ( <button className='nxt-temp-create-button' onClick={(e) => nxtInstallCall(e,true, "nexter-extension")}>{nexter_theme_builder_config?.extensionactivate ? __('Activate Nexter Extension', 'nexter-extension') : __('Install Nexter Extension', 'nexter-extension')}</button> )
                        :
                        ( menuActive === 'all' ?
                        <Dropdown variant="addNew" buttonText={__('Add New', 'nexter-extension')} svgIcon={addNewSVG} items={addNewDropdownItems} onSelect={(val) => setSelectTemp(val)} />
                        :
                        <button className='nxt-temp-create-button' onClick={(e) => handleNewClick(e, menuActive)}>{__('Add New', 'nexter-extension')}<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path fill="#fff" d="M9 3a.75.75 0 0 1 .75.75v4.5h4.5a.75.75 0 0 1 0 1.5h-4.5v4.5a.75.75 0 0 1-1.5 0v-4.5h-4.5a.75.75 0 0 1 0-1.5h4.5v-4.5A.75.75 0 0 1 9 3"/></svg></button> )
                    }
                </div>
            </div>

            <div className={"nxt-temp-cards type-"+ menuActive}>
                { menuActive === 'all' && filteredList.length === 0 && createTemp.map((card, index) => (
                    // ------------Default All Layout Card Structure------------ //
                    <div className="nxt-temp-crd" key={card.type}>
                        <div className="nxt-temp-img-cover">
                            <img src={nexter_theme_builder_config.assets+'svg/'+card.img} alt={card.type} />
                            <div className="nxt-temp-img-overlay">
                                {nexter_theme_builder_config.extensioninstall != '1' ? 
                                    <button className='nxt-temp-fill-blbtn naxt-temp-otline-btn' onClick={(e) => nxtInstallCall(e,true, "nexter-extension")}>{nexter_theme_builder_config?.extensionactivate ? __('Activate Nexter Extension', 'nexter-extension') : __('Install Nexter Extension', 'nexter-extension')}</button>
                                    :
                                    <button className="nxt-temp-fill-blbtn naxt-temp-otline-btn"  onClick={(e) => handleNewClick(e, card.type)}>
                                        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" >
                                            <path d="M8 3.33301V12.6663" stroke="#FFFFFF" strokeWidth="1.33333" strokeLinecap="round" strokeLinejoin="round" />
                                            <path d="M3.33398 8H12.6673" stroke="#FFFFFF" strokeWidth="1.33333" strokeLinecap="round" strokeLinejoin="round" />
                                        </svg>
                                        {card.btn}
                                    </button>
                                }
                            </div>
                        </div>

                        <div className="nxt-temp-crd-btm">
                            <div className="nxt-temp-ttl-strip">
                                <span className="nxt-temp-crd-ttl">
                                    {card.title}
                                </span>
                                <div className="nxt-temp-tooltip">
                                    <svg width="16" height="17" viewBox="0 0 16 17" fill="none" xmlns="http://www.w3.org/2000/svg">
                                        <path d="M8.00065 15.1663C11.6825 15.1663 14.6673 12.1816 14.6673 8.49967C14.6673 4.81778 11.6825 1.83301 8.00065 1.83301C4.31875 1.83301 1.33398 4.81778 1.33398 8.49967C1.33398 12.1816 4.31875 15.1663 8.00065 15.1663Z" stroke="#666666" strokeLinecap="round" strokeLinejoin="round" />
                                        <path d="M6.33398 6.83366C6.33398 5.91319 7.08018 5.16699 8.00065 5.16699C8.92112 5.16699 9.66732 5.91319 9.66732 6.83366C9.66732 7.40493 9.37992 7.90906 8.94178 8.20939C8.48618 8.52159 8.00065 8.94806 8.00065 9.50033" stroke="#666666" strokeLinecap="round" strokeLinejoin="round" />
                                        <path d="M8 11.833H8.00593" stroke="#666666" strokeLinecap="round" strokeLinejoin="round" />
                                    </svg>

                                    <span className="nxt-temp-tiptxt">
                                        <a href="#" onClick={openPopup}>
                                            {__("Click to Know How it Works", 'nexter-extension')}
                                        </a>
                                    </span>
                                </div>
                            </div>
                        </div>
                        {isPopupOpen && (
                            <>
                                <div className="nxt-temp-overlay" onClick={closePopup}></div>
                                <div className="nxt-temp-popup">
                                    <button className="nxt-temp-close-btn" onClick={closePopup}>✕</button>
                                    <div className="nxt-temp-pop-h">
                                        <h3 className="nxt-temp-md-h">{__('What is a Sections?', 'nexter-extension')}</h3>
                                        <span className="nxt-temp-sm-txt">{__('Reusable content blocks that can be placed anywhere on your site, like a banner, promo strip, or CTA. They save time since you design once and reuse across multiple pages.', 'nexter-extension')}</span>
                                    </div>
                                    <div className="nxt-temp-vid-box">
                                        <a href="#" target="_blank" rel="nofollow">
                                            <img className="nxt-temp-vid-img" src="https://etemplates.wdesignkit.com/shotbyscott/wp-content/uploads/sites/25/2025/10/image-3122.png" />
                                            <svg className="nxt-temp-yt-icon" xmlns="http://www.w3.org/2000/svg" width="76" height="52" fill="none" viewBox="0 0 76 52"><g><path fill="#f03" d="M37.496 51.772s23.517 0 29.35-1.553a9.38 9.38 0 0 0 6.621-6.549c1.603-5.747 1.603-17.836 1.603-17.836s0-12.01-1.603-17.706a9.2 9.2 0 0 0-6.621-6.549C61.012 0 37.496 0 37.496 0S14.03 0 8.224 1.58A9.45 9.45 0 0 0 1.55 8.127C0 13.823 0 25.834 0 25.834s0 12.09 1.55 17.836c.92 3.132 3.442 5.67 6.674 6.55 5.807 1.552 29.272 1.552 29.272 1.552"/><path fill="#fff" d="M49.184 25.886 29.77 14.885v22.003z"/></g><defs><clipPath ><path fill="#fff" d="M0 0h75.07v51.772H0z"/></clipPath></defs></svg>
                                        </a>
                                    </div>
                                </div>
                            </>
                        )}
                    </div>

                ))}
                {filteredList && filteredList.length > 0 && (
                    filteredList.map((temp) => {
                    const image = createTemp.find(item => item.type === temp.type_slug)
                    return (
                    <div className={"nxt-temp-crd" + (temp.id === trashLoadingId ? ' blink-animation' : '')} key={temp.id}>
                        <div className="nxt-temp-img-cover">
                            <div className={"nxt-temp-act-tag "+(temp.post_status == 'draft' ? 'nxt-temp-draft' : ((temp.status == '0') ? 'nxt-temp-inactive' : 'nxt-temp-active'))}>
                                <span className="nxt-temp-sm-tdt"></span>
                                <span className={"nxt-temp-actxt"}>{temp.post_status == 'draft' ? __('Draft', 'nexter-extension') : (statusLoadingId === temp.id ? (
                                    __('Updating...', 'nexter-extension')
                                ) : temp.status == '0' ? (
                                    __('Inactive', 'nexter-extension')
                                ) : (
                                    __('Active', 'nexter-extension')
                                ))}</span>
                            </div>
                            {menuActive === 'all' ? 
                                (image && image?.img ? <img src={`${nexter_theme_builder_config.assets}svg/${image.img}`} alt={`${temp.type_title}`} /> : <img src={`${nexter_theme_builder_config.assets}images/default.png`} alt={__('Theme builder template', 'nexter-extension')} />)
                                :
                                <iframe 
                                    src={temp.view+'?preview_template=true'} 
                                    loading="lazy"
                                    sandbox="allow-same-origin allow-scripts"
                                    className="nxt-preview-iframe">
                                </iframe>
                            }
                            
                            <div className="nxt-temp-img-overlay">
                                {nexter_theme_builder_config.extensioninstall != '1' ? 
                                    ( <button className='nxt-temp-fill-blbtn naxt-temp-otline-btn' onClick={(e) => nxtInstallCall(e,true, "nexter-extension")}>{nexter_theme_builder_config?.extensionactivate ? __('Activate Nexter Extension', 'nexter-extension') : __('Install Nexter Extension', 'nexter-extension')}</button> )
                                    :
                                    <a href={temp.edit_with_elementor || temp.edit} className="nxt-temp-fill-blbtn naxt-temp-otline-btn">
                                        <svg xmlns="http://www.w3.org/2000/svg" width="19" height="18" fill="none" viewBox="0 0 19 18"><path stroke="#fff" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9.5 15h6.75M12.875 2.625a1.591 1.591 0 1 1 2.25 2.25L5.75 14.25l-3 .75.75-3z" /></svg>
                                        {__('Edit ', 'nexter-extension') + temp.type_title}
                                    </a>
                                }
                            </div>
                        </div>

                        <div className="nxt-temp-crd-btm nxt-crd-ndt">
                            {menuActive === 'all' &&
                                <span className="nxt-temp-typtag"> {temp.type_title}</span>
                            }
                            <div className="nxt-temp-ttl-strip">
                                <a href={temp.edit_with_elementor || temp.edit} className="nxt-temp-crd-ttl">{temp.name}</a>
                                {(menuActive === 'header' || menuActive === 'footer') &&
                                    <div className="nxt-temp-user-info">
                                        <div className="nxt-temp-user-img">
                                            <img className="nxt-temp-uimg" src={temp.author_avtar} alt={temp.author_name} />
                                        </div>
                                        <span className="nxt-temp-usnm">{temp.author_name}</span>
                                        <span className="nxt-temp-crd-sep">|</span>
                                        <div className="nxt-temp-last-upd">
                                            <span className="nxt-temp-lud-txt">{__('Last Updated :', 'nexter-extension')}</span>
                                            <span className="nxt-temp-lud-dt">{temp.last_updated}</span>
                                        </div>
                                    </div>
                                }
                                <Dropdown items={dotsDropdownItems} tempData={temp} svgIcon={dotsSVG} onSelect={(val) => setAction(val)} />
                            </div>
                            {(menuActive != 'header' && menuActive != 'footer') && (
                                <div className="nxt-temp-user-info">
                                    <div className="nxt-temp-user-img">
                                        <img className="nxt-temp-uimg" src={temp.author_avtar} alt={temp.author_name} />
                                    </div>
                                    <span className="nxt-temp-usnm">{temp.author_name}</span>
                                </div>
                            )}
                        </div>
                    </div>
                    )})
                )}
            </div>
            { menuActive != 'all' && filteredList.length === 0 &&
                <NoTemplate  menuActive={menuActive} menuActiveLabel={menuActiveLabel} />
            }
        </div>
    );
};

export default AllLayout;
