import React, { useState, useEffect, useRef } from 'react';
import './dropdown.scss';
import { __ } from '@wordpress/i18n';
import { listGet, nxt_temp_fetch_api } from '../../apicall';
import { useDispatch, useSelector } from "react-redux";
import { handleThemeBuilderData, setStatusLoading, setTrashLoading, handleThemeBuilderInfo } from "../../redux/slice";

const Dropdown = ({ items, tempData, buttonText, svgIcon, onSelect, variant }) => {
    const [isDropdownVisible, setDropdownVisible] = useState(false);
    const dropdownButtonRef = useRef(null);
    const dropdownListRef = useRef(null);
    const [copiedId, setCopiedId] = useState(null);

    const dispatch = useDispatch();

    const toggleDropdown = () => {
        setDropdownVisible(!isDropdownVisible);
    };

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (
                dropdownButtonRef.current && !dropdownButtonRef.current.contains(event.target) &&
                dropdownListRef.current && !dropdownListRef.current.contains(event.target)
            ) {
                setDropdownVisible(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const handleSelect = async (item) => {
        onSelect && onSelect(item);
        setDropdownVisible(false);

        if(item.value==='status'){
            dispatch(setStatusLoading(tempData.id));
            let args = new URLSearchParams({
                action: 'nexter_ext_status',
                nexter_nonce: nexter_admin_config.ajax_nonce,
                post_id: tempData.id,
                check: tempData.status == '0' ? 1 : 0,
            });
            const res = await nxt_temp_fetch_api(args);

            if (res.success) {
                const updatedList = await listGet();
                dispatch(handleThemeBuilderData(updatedList?.templates || {}));
                dispatch(handleThemeBuilderInfo(updatedList?.info || {}));
            }
            dispatch(setStatusLoading(null));
        }else if(item.value==='trash'){
            dispatch(setTrashLoading(tempData.id));
            let args = new URLSearchParams({
                action : 'nexter_ext_builder_update',
                nexter_nonce : nexter_admin_config.ajax_nonce,
                post_id : tempData.id,
                updated : 'trash',
            });
            const res = await nxt_temp_fetch_api(args);
            if (res.success) {
                const updatedList = await listGet();
                dispatch(handleThemeBuilderData(updatedList?.templates || {}));
                dispatch(handleThemeBuilderInfo(updatedList?.info || {}));
            }
            dispatch(setStatusLoading(null));
        }else if(item.value==='duplicate'){
            dispatch(setStatusLoading(tempData.id));
            let args = new URLSearchParams({
                action: 'nxt_duplicate_post',
                nexter_nonce: nexter_admin_config.ajax_nonce || nexter_theme_builder_config.ajax_nonce,
                original_id: tempData.id,
                total: 1,
            });
            const res = await nxt_temp_fetch_api(args);
            if (res.success) {
                const updatedList = await listGet();
                dispatch(handleThemeBuilderData(updatedList?.templates || {}));
                dispatch(handleThemeBuilderInfo(updatedList?.info || {}));
            }
            dispatch(setStatusLoading(null));
        }else if (item.value === 'copy_shortcode') {
            const shortcode = `[nexter-builder id="${tempData.id}"]`;

            if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(shortcode);
            } else {
                const textarea = document.createElement("textarea");
                textarea.value = shortcode;
                document.body.appendChild(textarea);
                textarea.select();
                document.execCommand("copy");
                textarea.remove();
            }
            setCopiedId(tempData.id);

            setTimeout(() => {
                setCopiedId(null);
            }, 200);

        }
    };

    const handleEditClick = (e) => {
        const builder = new window.NexterBuilder();
        builder.nextOpenCondition(e, '', 'edit');
    }
    const handleNewClick = (e, type='') => {
        const builder = new window.NexterBuilder();
        let action = 'action=nexter_ext_temp_popup&nexter_nonce=' + nexter_theme_builder_config.ajax_nonce;
        builder.nxtBuilderCommon(action, true, type);
    }

    return (
        <div className="nxt-temp-dp-btn" ref={dropdownButtonRef} onClick={toggleDropdown}>
            <div className='nxt-temp-drpbtn-lbl'>
                <span className="nxt-temp-btn-text">{buttonText}</span>
                <span className="nxt-temp-dots-i">
                    {svgIcon}
                </span>
            </div>

            {isDropdownVisible && (
                <div className="nxt-temp-drpdwn-list" ref={dropdownListRef}>
                    {items.map((item, index) => (
                    item.value === 'status' ? (
                        <span
                            key={index}
                            className="nxt-temp-lst-itm"
                            onClick={() => handleSelect(item)}
                        >
                            {tempData.status == '0'
                                ? __('Active', 'nexter-extension')
                                : __('Deactivate', 'nexter-extension')}
                        </span>
                    ) : item.value === 'edit_conditions' ? (
                        <span
                            key={index}
                            className="nxt-temp-lst-itm nexter-conditions-action"
                            onClick={(e) => {handleSelect(item), handleEditClick(e) }}
                            data-post={tempData.id}
                            data-type={tempData.section_page}
                            data-subtype={tempData.type_slug}
                        >
                            {item.label}
                        </span>
                    ) : item.value === 'preview' ? (
                        <a
                            key={index}
                            className="nxt-temp-lst-itm nxt-previewlink"
                            href={tempData.view}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            {item.label}
                        </a>
                    ) : item.value === 'export' ? (
                        <a
                            key={index}
                            className="nxt-temp-lst-itm nxt-previewlink"
                            href={tempData.export}
                            rel="noopener noreferrer"
                        >
                            {item.label}
                        </a>
                    ) : variant === 'addNew' ? (
                        <span
                            key={index}
                            className="nxt-temp-lst-itm"
                            onClick={(e) => {handleSelect(item), handleNewClick(e, item.value)}}
                        >
                            {item.label}
                        </span>
                    ) : (
                        <span
                            key={index}
                            className="nxt-temp-lst-itm"
                            onClick={() => handleSelect(item)}
                        >
                            {item.value === 'copy_shortcode' && copiedId === tempData.id
                                ? __("Copied!", 'nexter-extension')
                                : item.label}
                        </span>
                    )
                ))}

                </div>
            )}
        </div>
    );
};

export default Dropdown;