import './style/main.scss';
import React from 'react';
import { createRoot } from 'react-dom/client';
import domReady from '@wordpress/dom-ready';
import App from "./App";
domReady(() => {
  const target = document.getElementById('nexter-theme-builder');
  if (target) {
    const root = createRoot(target);
    root.render(<App />);
  } else {
    console.error('Target element not found: #nexter-theme-builder');
  }
});


