import { __ } from '@wordpress/i18n';

export const nxt_temp_fetch_api = async (args) => {
    if (args) {        
        try {
            const response = await fetch(nexter_theme_builder_config?.ajaxurl || nxtext_ajax_object?.ajax_url, {
                method: 'POST',
                body: args
            });

            if (!response.ok) {
                throw new Error(`HTTP error! Status: ${response.status}`);
            }

            const data = await response.json();
            return data;
        } catch (error) {
            return error.message;
        }
    } else {
        return false;
    }
}

export const listGet = async () => {
    const response = await fetch(nexter_theme_builder_config?.ajaxurl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
            action: 'nexter_ext_temp_listout',
            nonce: nexter_theme_builder_config.ajax_nonce,
        }),
    });

    const data = await response.json();

    if (data.success) {
        return data.data;
    } else {
        return __( 'Failed to fetch templates.', 'nexter-extension' );
    }
}

export const updateStatus = async (post_id, check) => {
    const response = await fetch(nexter_admin_config.ajaxurl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
            action: 'nexter_ext_status',
            nexter_nonce: nexter_admin_config.ajax_nonce,
            post_id: post_id,
            check: check,
        }),
    });

    const data = await response.json();
    return data;
};

export const appendFormData = (form, data) => {
    for (const key in data) {
        if (data.hasOwnProperty(key)) {
            form.append(key, data[key]);
        }
    }
};
export const nxtInstallCall = async (e, reload = true, slug="") => {
    let ajxData = new FormData(),
        formData = {};
    if(nexter_theme_builder_config?.tpae){
        Object.assign(formData, {
            action: 'tpae_dashboard_ajax_call',
            type : 'tpae_plugin_install',
            slug : slug,
            nonce: nexter_theme_builder_config?.tpae_nonce || '',
            name: slug,
        });
    }else{
        Object.assign(formData, {
            action: 'nexter_ext_plugin_install',
            slug : slug,
            nexter_nonce: nexter_theme_builder_config?.ajax_nonce || nxtext_ajax_object?.ajax_nonce || '',
        });
    }
    
    appendFormData(ajxData, formData);
    if(slug=='wdesignkit' && nexter_theme_builder_config?.wdkactive != '1'){
        e.target.innerHTML = __( 'Activating WDesignKit', 'nexter-extension' );
    }else if(slug=='wdesignkit' && nexter_theme_builder_config?.wdkactive == '1'){
        e.target.innerHTML = __( 'Installing Nexter Extension', 'nexter-extension' );
    }else if (slug === 'nexter-extension' && nexter_theme_builder_config?.extensionactivate != '1') {
        e.target.innerHTML = __( 'Activating Nexter Extension', 'nexter-extension' );
    }else if (slug === 'nexter-extension' && nexter_theme_builder_config?.extensionactivate == '1') {
        e.target.innerHTML = __( 'Activating Nexter Extension', 'nexter-extension' );
    }
    try {
        const response = await nxt_temp_fetch_api(ajxData);
        const data = await response;

        if (data) {
            setTimeout(() => {
                if(slug=='wdesignkit'){
                    e.target.innerHTML = __( 'Activate WDesignKit', 'nexter-extension' );
                }else if (slug === 'nexter-extension') {
                    e.target.innerHTML = __( 'Activate Nexter Extension', 'nexter-extension' );
                }
            }, 2000);
            if(slug=='wdesignkit'){
                nexter_theme_builder_config.wdkPlugin = data.Success;
            }else if (slug === 'nexter-extension') {
                nexter_theme_builder_config.extensioninstall = data.Success;
            }
            if(reload){
                window.location.reload();
            }
        }
    } catch (error) {
        console.error('Error in Cache :', error);
    }
}