import './theme-dash-main.scss'
import { __ } from '@wordpress/i18n';

import AllLayout from "../all-layout/all-layout";
import { useDispatch, useSelector } from "react-redux";
import { handleThemeBuilderData, handleThemeBuilderInfo } from "../../redux/slice";
import { listGet, nxt_temp_fetch_api } from "../../apicall";

const tabs = [
    {
        key: "all",
        lbl: __('All Layout', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M15.082 15.082c-1.044 1.043-2.723 1.043-6.082 1.043s-5.038 0-6.082-1.043C1.875 14.038 1.875 12.359 1.875 9s0-5.038 1.043-6.082C3.962 1.875 5.641 1.875 9 1.875s5.038 0 6.082 1.043C16.125 3.962 16.125 5.641 16.125 9s0 5.038-1.043 6.082"/><path stroke="#666" strokeWidth="1.5" d="M6.75 16.125V1.875M16.125 9H6.75"/></svg>
    },
    {
        key: "header",
        lbl: __('Header', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M2.918 15.082C1.875 14.038 1.875 12.359 1.875 9s0-5.038 1.043-6.082C3.962 1.875 5.641 1.875 9 1.875s5.038 0 6.082 1.043C16.125 3.962 16.125 5.641 16.125 9s0 5.038-1.043 6.082c-1.044 1.043-2.723 1.043-6.082 1.043s-5.038 0-6.082-1.043"/><path stroke="#666" strokeWidth="1.5" d="M1.875 6.75h14.25"/></svg>
    },
    {
        key: "footer",
        lbl: __('Footer', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M2.918 2.918C1.875 3.962 1.875 5.641 1.875 9s0 5.038 1.043 6.082C3.962 16.125 5.641 16.125 9 16.125s5.038 0 6.082-1.043c1.043-1.044 1.043-2.723 1.043-6.082s0-5.038-1.043-6.082C14.038 1.875 12.359 1.875 9 1.875s-5.038 0-6.082 1.043"/><path stroke="#666" strokeWidth="1.5" d="M1.875 11.25h14.25"/></svg>
    },
    {
        key: "breadcrumb",
        lbl: __('Breadcrumbs', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9.375 13.5s4.5-3.314 4.5-4.5-4.5-4.5-4.5-4.5M4.125 13.5s4.5-3.314 4.5-4.5-4.5-4.5-4.5-4.5"/></svg>
    },
    {
        key: "section",
        lbl: __('Section', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeWidth="1.5" d="M1.5 4.875c0-1.053 0-1.58.253-1.958a1.5 1.5 0 0 1 .414-.414c.378-.253.905-.253 1.958-.253h9.75c1.053 0 1.58 0 1.958.253.164.11.305.25.414.414.253.378.253.905.253 1.958s0 1.58-.253 1.958a1.5 1.5 0 0 1-.414.414c-.378.253-.905.253-1.958.253h-9.75c-1.053 0-1.58 0-1.958-.253a1.5 1.5 0 0 1-.414-.414C1.5 6.455 1.5 5.928 1.5 4.875ZM1.5 13.125c0-1.053 0-1.58.253-1.958a1.5 1.5 0 0 1 .414-.414c.378-.253.905-.253 1.958-.253h9.75c1.053 0 1.58 0 1.958.253.164.11.305.25.414.414.253.378.253.905.253 1.958s0 1.58-.253 1.958c-.11.164-.25.305-.414.414-.378.253-.905.253-1.958.253h-9.75c-1.053 0-1.58 0-1.958-.253a1.5 1.5 0 0 1-.414-.414c-.253-.378-.253-.905-.253-1.958Z"/></svg>
    },
    {
        key: "singular",
        lbl: __('Single Page', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><g stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" clipPath="url(#a)"><path d="M6 12.75h6M6 9.75h3M9.75 1.875v.375c0 2.121 0 3.182.659 3.841.66.659 1.72.659 3.841.659h.375M15 7.993V10.5c0 2.828 0 4.243-.879 5.121-.878.879-2.293.879-5.121.879s-4.243 0-5.121-.879C3 14.743 3 13.328 3 10.5V7.092c0-2.434 0-3.65.665-4.475a3 3 0 0 1 .452-.452C4.941 1.5 6.158 1.5 8.592 1.5c.529 0 .794 0 1.036.086q.076.026.148.06c.232.112.419.299.793.673L14.12 5.87c.434.434.65.65.765.926S15 7.38 15 7.993"/></g><defs><clipPath id="a"><path fill="#fff" d="M0 0h18v18H0z"/></clipPath></defs></svg>
    },
    {
        key: "archives",
        lbl: __('Archive Page', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M15.75 5.25H2.25v4.5c0 2.828 0 4.243.879 5.121.878.879 2.293.879 5.121.879h1.5c2.828 0 4.243 0 5.121-.879.879-.878.879-2.293.879-5.121zM15.75 5.25H2.25l.9-1.2c.662-.883.994-1.325 1.469-1.562S5.646 2.25 6.75 2.25h4.5c1.104 0 1.656 0 2.131.238.475.237.806.679 1.469 1.562z"/><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9 12.75V7.875m-2.25 3c.442.455 1.62 2.25 2.25 2.25s1.808-1.795 2.25-2.25"/></svg>
    },
    /* {
        key: "sr",
        lbl: __('Search Page', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="19" height="18" fill="none" viewBox="0 0 19 18"><path stroke="#666" d="m13.25 12.75 3 3m-1.5-7.5a6 6 0 1 0-12 0 6 6 0 0 0 12 0" /></svg>
    }, */
    {
        key: "hooks",
        lbl: __('Hooks', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="m12.75 6 1.38 1.388c.58.583.87.875.87 1.237s-.29.654-.87 1.237l-1.38 1.388M5.25 6 3.87 7.388C3.29 7.97 3 8.263 3 8.625s.29.654.87 1.237l1.38 1.388M10.875 3l-3.75 12"/></svg>
    },
    {
        key: "page-404",
        lbl: __('404 Page', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 18 18"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M10.444 15.75H7.556c-3.472 0-5.209 0-5.849-1.13S1.956 11.994 3.732 9l1.443-2.434C6.882 3.688 7.735 2.25 9 2.25s2.118 1.438 3.825 4.315l1.443 2.434c1.776 2.994 2.665 4.492 2.025 5.621s-2.377 1.13-5.85 1.13M9 6.75v3.375M9 12.744v.008"/></svg>
    },
    /* {
        key: "cm",
        lbl: __('Coming Soon & Maintenance', 'nexter-extension'),
        ico: <svg xmlns="http://www.w3.org/2000/svg" width="19" height="18" fill="none" viewBox="0 0 19 18"><path stroke="#666" d="M15.769 10.018c-.892.891-2.57.857-5.145.857a3 3 0 0 1-2.999-3c0-2.572-.035-4.252.858-5.144.892-.892 1.286-.856 5.238-.856a.428.428 0 0 1 .304.73L11.99 4.64a1.323 1.323 0 1 0 1.87 1.87l2.034-2.034a.428.428 0 0 1 .73.304c0 3.952.037 4.346-.855 5.238Z" /><path stroke="#666" d="m10.625 10.875-4.629 4.629a2.121 2.121 0 0 1-3-3l4.629-4.629M4.632 13.875h-.007" /></svg>
    }, */
];

const ThemeBuilder = () => {
    const [active, setActive] = useState("all");
    const [activeLabel, setActiveLabel] = useState(__('All', 'nexter-extension'));
    const [isPopupOpen, setIsPopupOpen] = useState(false);
    const ThemeBuilderInfo = useSelector((state) => state.themebuilderinfo);
    const dispatch = useDispatch();

    const fetchData = async () => {
        const list = await listGet();
        dispatch(handleThemeBuilderData(list?.templates || {}));
        dispatch(handleThemeBuilderInfo(list?.info || {}));
    };

    useEffect(() => {
        if(nexter_theme_builder_config.extensioninstall == '1'){
            fetchData();
        }else{
            dispatch(handleThemeBuilderData({}));
            dispatch(handleThemeBuilderInfo({}));
        }
    }, [dispatch]);


    const [customizerFile, setcustomizerFile] = useState(null);
    const [fileName, setFileName] = useState(__('--Choose File--', 'nexter-extension'));
    const [message, setMessage] = useState('');
    const [isError, setIsError] = useState(false);
    const [isProcess, setProcess] = useState('');
    const fileInputRef = useRef(null);

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        setcustomizerFile(file)
        setFileName(file ? file.name : __('--Choose File--', 'nexter-extension'));
    };

    const nxtImportData = (e) => {
        e.preventDefault();

        if (!customizerFile) {
            setMessage(__('Please select a file to import.', 'nexter-extension'));
            setIsError(true);
            return;
        }

        const formData = new FormData();
            formData.append('action', 'nxt_builder_import_actions');
            formData.append('_nonce', nexter_theme_builder_config?.import_temp_nonce); // nonce 
            formData.append('file', customizerFile);
            formData.append('nxt_action', 'import_template');
            formData.append('after_import', 'no');
        
        setMessage('');
        setIsError(false);
        setProcess(__('Importing…', 'nexter-extension'))
        fetch(nxtext_ajax_object?.ajax_url, {
            method: 'POST',
            body: formData,
        })
        .then(res => res.json())
        .then(response => {
            if (response.success) {
                setMessage(response.data || __('Import successful!', 'nexter-extension'));
                setIsError(false);
                setcustomizerFile(null); // optional: reset file input
                setFileName(__('--Choose File--', 'nexter-extension'));
                fetchData();
                if (fileInputRef.current) fileInputRef.current.value = '';
                setProcess(__('Imported', 'nexter-extension'))
                setTimeout(() => {
                    setMessage('');
                    setProcess(__('Import', 'nexter-extension'))
                    setIsPopupOpen(false);
                    setcustomizerFile(null);
                    setFileName(__('--Choose File--', 'nexter-extension'));
                }, 1500);
            } else {
                setMessage(response.data || __('Import failed.', 'nexter-extension'));
                setIsError(true);
                setProcess(__('Import', 'nexter-extension'))
            }
        })
        .catch(() => {
            setMessage(__('An error occurred during import.', 'nexter-extension'));
            setIsError(true);
            setProcess(__('Import', 'nexter-extension'))
        });
    };

    const openPopup = (e) => {
        e.preventDefault();
        setcustomizerFile(null);
        setFileName(__('--Choose File--', 'nexter-extension'));
        setIsPopupOpen(true);
        setIsError(false);
    };

    const closePopup = () => {
        setIsPopupOpen(false);
    };

    const handleToggleChange = async (e) => {
        const checked = e.target.checked;
        const updatedInfo = { ...ThemeBuilderInfo, switcher: checked };
        dispatch(handleThemeBuilderInfo(updatedInfo));
        try {
            const args = new URLSearchParams({
                action: "nexter_ext_builder_update",
                nexter_nonce: nexter_admin_config.ajax_nonce,
                updated: 'switcher',
                checked : checked
            });

            const res = await nxt_temp_fetch_api(args);
            if (res.success) {
                if( checked === false ){
                   window.location.href = `${nexter_theme_builder_config.adminUrl}edit.php?post_type=nxt_builder`;
                }
                const updatedInfo = { ...ThemeBuilderInfo, switcher: checked };
                dispatch(handleThemeBuilderInfo(updatedInfo));
            } else {
                console.error("Update failed:", res);
            }
        } catch (error) {
        console.error("Error updating template:", error);
        }
    };
    
    const isChecked = (ThemeBuilderInfo?.switcher === true || ThemeBuilderInfo?.switcher === 'true' || ThemeBuilderInfo?.switcher === 1 || ThemeBuilderInfo?.switcher === '1' || ThemeBuilderInfo?.switcher == undefined);

    return (
        <div className="nxt-temp-app">
            {isPopupOpen && (
            <>
                <div className="nxt-temp-overlay" onClick={closePopup}></div>
                <div className="nxt-temp-popup">
                    <button className="nxt-temp-close-btn" onClick={closePopup}>✕</button>
                    <div className="nxt-temp-pop-h">
                        <h3 className="nxt-temp-md-h">{__('Import Templates', 'nexter-extension')}</h3>
                        <span className="nxt-temp-sm-txt">{__('Choose a Nexter Theme Builder template XML file of Builder templates, and add them to the list of templates available in your builder.', 'nexter-extension')}</span>
                    </div>
                    <div className="nxt-temp-content-box">
                        <div className="nxtext_strip_tgl_cover nxtext_full_strip_tgl nxt-export-wrap">
                            <form className="nxp-flex-between nxp-w-full" onSubmit={(e) => nxtImportData(e)} encType="multipart/form-data">
                                <label className='nxp-tg__item-label-row nxp-tg__item-label nxp-body' htmlFor={"theme-builder-temp"}>{__("Choose Template", 'nexter-extension')}</label>
                                <div className={"custom-file-wrapper nxp-border nxp-flex-center nxp-overflow-hidden nxp-rounded-sm nxp-w-full"+(customizerFile !=null ? ' active-choose-file' : '')}>
                                    <label htmlFor="customFileInput" className="custom-file-button nxp-bg-default nxp-cursor-pointer nxp-flex-center nxp-px-10 nxp-text-primary nxp-w-full"><span className={"custom-file-label nxp-border-r nxp-grow nxp-overflow-hidden nxp-p-4 nxp-text-muted "+(customizerFile !=null ? ' active-choose-file' : '')}>{fileName}</span>
                                        {__('Choose File', 'nexter-extension')}
                                    </label>
                                    <input type="file" id="customFileInput" name="nxt_import_file" className="nxp-hidden" onChange={(e) => handleFileChange(e)} ref={fileInputRef} required />
                                </div>
                                <button type="submit" className="nxp-btn nxp-btn--outline nxp-btn--sm">{isProcess ? isProcess : __('Import', 'nexter-extension')}</button>
                            </form>
                        </div>
                        {message && (
                            <div className={isError ? 'nxt-ext-error-message' : 'nxt-ext-success-message'}>
                                {message}
                            </div>
                        )}
                    </div>
                </div>
            </>
            )}
            <div className="nxt-temp-top">
                <div className="nxt-temp-logo">
                    <a href={nexter_theme_builder_config.dashboard_url} className="nxt-temp-ttl">
                        {((nexter_theme_builder_config.is_pro && nxtext_ajax_object?.dashData?.whiteLabel?.theme_logo)
                                ? <img src={nxtext_ajax_object?.dashData?.whiteLabel?.theme_logo} alt={__('Theme Builder', 'nexter-extension')} />
                                : (<>
                                <svg className="nxt-normal-theme-logo" xmlns="http://www.w3.org/2000/svg" width="28" height="28" fill="none" viewBox="0 0 28 28"><rect width="28" height="28" fill="#1717cc" rx="5.833" /><path fill="#fff" d="M12.834 5.32h2.917v11.958a.875.875 0 0 1-.875.875h-2.042zM12.834 19.903h2.042c.483 0 .875.391.875.875v2.041h-2.917z" /></svg>

                                <svg className="nxt-hover-theme-back" xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="none" viewBox="0 0 24 24"><path stroke="#000" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 12H5M12 19l-7-7 7-7" /></svg>
                                </>
                                )
                            )
                        }
                        {__('Theme Builder', 'nexter-extension')}
                    </a>
                </div>
                {nexter_theme_builder_config.extensioninstall != '1' &&
                    <div className="nxt-temp-install-ext">
                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="none" viewBox="0 0 20 20"><path stroke="#666" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.667" d="M10 18.334a8.333 8.333 0 1 0 0-16.667 8.333 8.333 0 0 0 0 16.667M10 13.333V10M10 6.667h.008"/></svg>
                        {__('Please Install Nexter Extension to Enable Theme Builder.', 'nexter-extension')}
                    </div>
                }
                {nexter_theme_builder_config.extensioninstall== '1' &&
                    <div className="nxt-temp-top-btns">
                        <button className="naxt-temp-otline-btn nxt-temp-blue-btn" onClick={openPopup}>{__('Import Templates', 'nexter-extension')}</button>

                        <div className="nxt-temp-tbl-switch">
                            <div className="nxt-temp-sw-cover">
                                <input className="nxt-temp-tgl-btn" id="nxt_thtgl_sw" type="checkbox" checked={isChecked} onChange={handleToggleChange} />
                                <label className="nxt-temp-sw-lbl" htmlFor="nxt_thtgl_sw">
                                    <span className="nxt-temp-switch-btn"></span>
                                </label>
                            </div>
                            <label htmlFor="nxt_thtgl_sw" className="nxt-temp-sw-nm">{__('Switch to table view', 'nexter-extension')}</label>
                        </div>
                        <a href={nexter_theme_builder_config.dashboard_url} className="nxt-temp-go-dashboard">✕</a>
                    </div>
                }
                
            </div>

            <div className="nxt-temp-body">
                <div className="nxt-temp-left">
                    <div className="nxt-temp-nav">
                        {tabs.map((t) => (
                            <div
                                key={t.key}
                                className={"nxt-temp-tab" + (active === t.key ? " nxt-temp-active" : "")}
                                data-tab={t.key}
                                onClick={() => {setActive(t.key),setActiveLabel(t.lbl)}}
                            >
                                <div className="nxt-temp-ico">{t.ico}</div>
                                <div className="nxt-temp-txt">{t.lbl}</div>
                            </div>
                        ))}
                    </div>

                    <div className="nxt-temp-nav-btm">
                        {nexter_theme_builder_config.is_pro == false ?
                            <a href={'https://nexterwp.com/pricing/?utm_source=wpbackend&utm_medium=themebuilder&utm_campaign=nextersettings'} rel="noopener noreferrer" target="_blank" className="nxt-temp-sb-link">
                                <span>{__('Upgrade Now', 'nexter-extension')}</span>
                                <svg xmlns="http://www.w3.org/2000/svg" width="19" height="20" fill="none" viewBox="0 0 19 20"><rect width="18.5" height="18.5" x=".25" y=".75" fill="#f9b744" rx="9.25" /><rect width="18.5" height="18.5" x=".25" y=".75" stroke="#f9b744" strokeWidth=".5" rx="9.25" /><path fill="#fff" d="m5.574 11.168-.57-3.707a.31.31 0 0 1 .491-.295L7.272 8.5a.425.425 0 0 0 .608-.104l1.479-2.22a.395.395 0 0 1 .657 0l1.48 2.22c.134.202.412.25.607.104l1.777-1.333a.31.31 0 0 1 .491.295l-.57 3.707zM13.372 13.225H6.003a.43.43 0 0 1-.429-.43v-.941h8.227v.942a.43.43 0 0 1-.429.429" /></svg>
                            </a>
                            :
                            (nexter_theme_builder_config.is_pro && nxtext_ajax_object?.dashData?.whiteLabel?.nxt_licence_tab != 'on' && <a href={nexter_theme_builder_config.dashboard_url+'#/activate_PRO'} rel="noopener noreferrer" target="_blank" className="nxt-temp-sb-link">
                               {nexter_theme_builder_config?.keyActmsg?.status == 'valid' ? <>
                                {__('Activated Now', 'nexter-extension')}
                                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="none" viewBox="0 0 11 12">
                                    <path fill="#14C38E" d="M5.086.778c-.798.076-1.404.245-2.067.579A5.698 5.698 0 0 0 .806 3.386C.421 4 .141 4.794.027 5.589a8.373 8.373 0 0 0 0 1.354c.09.634.259 1.189.52 1.72a5.094 5.094 0 0 0 1.063 1.485c.476.473.887.767 1.465 1.051a4.82 4.82 0 0 0 1.075.398 5.461 5.461 0 0 0 3.205-.153 6.67 6.67 0 0 0 1.162-.582 5.857 5.857 0 0 0 1.654-1.694c.154-.243.404-.759.505-1.045a5.452 5.452 0 0 0-.247-4.284 5.265 5.265 0 0 0-.985-1.393 5.25 5.25 0 0 0-1.53-1.113A5.264 5.264 0 0 0 5.98.785a7.327 7.327 0 0 0-.893-.007Z"></path>
                                    <path fill="#fff" d="M7.604 4.47c-.029.012-.759.73-1.621 1.597L4.41 7.64l-.585-.587c-.632-.632-.637-.634-.82-.598a.363.363 0 0 0-.244.245c-.035.187-.047.173.753.975.8.803.784.79.973.755.07-.012.273-.208 1.806-1.743 1.254-1.258 1.731-1.748 1.748-1.8a.34.34 0 0 0-.13-.383.413.413 0 0 0-.308-.035Z"></path>
                                </svg>
                                </> : __('Activate Now', 'nexter-extension')}
                            </a>)
                        }
                        
                        {!(nexter_theme_builder_config.is_pro && nxtext_ajax_object?.dashData?.whiteLabel?.nxt_help_link == 'on') &&
                            <div className="nxt-temp-btm-sminfo">
                                <span className="nxt-temp-sm-inf">{__('Version ', 'nexter-extension')+nexter_theme_builder_config.version}</span>
                                <span className="nxt-temp-divider"></span>
                                <a href={`${nexter_theme_builder_config.adminUrl}site-health.php?tab=debug`} rel="noopener noreferrer" target="_blank" className="nxt-temp-sm-inf">{__('System Info', 'nexter-extension')}</a>
                            </div>
                        }
                        
                    </div>
                </div>

                <div className="nxt-temp-main">
                    <div className="nxt-temp-pane nxt-temp-active" data-tab={active}>
                        <div className="nxt-temp-panein">
                            <AllLayout menuActive={active} menuActiveLabel={activeLabel} />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ThemeBuilder;