import { createSlice } from "@reduxjs/toolkit";

const initialState = {
    templates: null,
    themebuilderinfo: null,
    statusLoadingId: null,
    trashLoadingId: null,
};

const Slice = createSlice({
    name: 'Slice',
    initialState,
    reducers: {
        handleThemeBuilderData: (state, action) => {
            state.templates = action.payload;
        },
        handleThemeBuilderInfo: (state, action) => {
            state.themebuilderinfo = action.payload;
        },
        setStatusLoading: (state, action) => {
            state.statusLoadingId = action.payload;
        },
        setTrashLoading: (state, action) => {
            state.trashLoadingId = action.payload;
        },
    },
});

export const { handleThemeBuilderData, setStatusLoading, setTrashLoading, handleThemeBuilderInfo } = Slice.actions;
export default Slice.reducer;
